import type { Metadata } from "next";

import { CraftUnlocker } from "./CraftUnlocker";

const encryptedPageJson = "{\"label\":\"Pnevma Craft price list\",\"algorithm\":\"AES-256-GCM\",\"kdf\":\"PBKDF2-SHA-256\",\"iterations\":310000,\"salt\":\"34Z9U29pmxol7qF2MWilVw==\",\"iv\":\"E36XTb3E7WUeTsBT\",\"ciphertext\":\"\"}";

export const metadata: Metadata = {
  title: "Pnevma Craft Access",
  robots: {
    index: false,
    follow: false,
    nocache: true,
  },
};

export default function CraftPage() {
  const encryptedKilobytes = Math.ceil(JSON.parse(encryptedPageJson).ciphertext.length * 0.75 / 1024);

  return <CraftUnlocker encryptedPageJson={encryptedPageJson} encryptedKilobytes={encryptedKilobytes} />;
}
